import { useState, useMemo } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is standard deviation?", a: "Standard deviation (SD) measures how spread out values are around the mean (average). A low SD means data points are clustered close to the mean - consistent results. A high SD means they're widely spread - high variability. It is the square root of variance and is expressed in the same units as the original data." },
  { q: "What is the difference between population and sample standard deviation?", a: "Population SD (, denoted with n denominator) is used when you have data for the entire group you're measuring. Sample SD (s, denoted with n- denominator - Bessel's correction) is used when your data is a subset of a larger population. The n- correction makes the sample SD an unbiased estimator of the population SD. In practice, sample SD is more commonly used." },
  { q: "What does the standard deviation tell you?", a: "In a normal distribution (bell curve): 68.2% of data falls within - SD of the mean, 95.4% within - SD, and 99.7% within - SD. This is called the empirical rule (or 68-95-99.7 rule). It helps identify outliers (values beyond - SD), assess data quality, and understand how representative the mean is." },
  { q: "How is variance different from standard deviation?", a: "Variance is the average of squared differences from the mean: Var = BP(x-^2 / n. Standard deviation = -ce. SD is in the original data's units (easier to interpret), while variance is in squared units. Example: if data is in kilograms, variance is in kg- but SD is in kg - directly comparable to data points." },
  { q: "What is the coefficient of variation (CV)?", a: "CV = (Standard Deviation  x  Mean)  x  100%. It expresses SD as a percentage of the mean, enabling comparison of variability across datasets with different units or scales. CV < 15% = low variability, 15-30% = moderate, > 30% = high. A dataset with mean 100 and SD 10 has CV = 10%. One with mean 5 and SD 0.5 also has CV = 10% - same relative spread." },
  { q: "How do you calculate standard deviation step by step?", a: "1. Find the mean: sum all values  x  count. 2. Subtract the mean from each value to get deviations. 3. Square each deviation. 4. Sum all squared deviations. 5. Divide by n (population) or n- (sample) to get variance. 6. Take the square root to get standard deviation. This calculator performs all steps instantly." },
  { q: "What is a z-score and how is it related to SD?", a: "A z-score measures how many standard deviations a value is from the mean: z = (x - mean) / SD. A z-score of +2 means the value is 2 standard deviations above the mean. Z-scores allow comparison across different datasets and are used in statistics, quality control, and standardized testing (SAT scores use z-score transformations)." },
  { q: "What is a normal distribution?", a: "A normal distribution (bell curve) is a symmetric probability distribution where the mean, median, and mode are all equal. Standard deviation defines the shape - a smaller SD makes a taller, narrower bell; larger SD makes a flatter, wider bell. Many natural phenomena follow normal distributions: heights, IQ scores, measurement errors, and manufacturing tolerances." },
];

const EXAMPLES = [
  ["Heights (women, US)", "63.7, 64.2, 65.1, 62.8, 65.5, 64.0", "Mean: 64.2, SD - 1.1 in"],
  ["Exam scores", "72, 85, 91, 68, 77, 88, 95, 74", "Mean: 81.3, SD - 9.4"],
  ["Die rolls (6-sided)", "1, 2, 3, 4, 5, 6", "Mean: 3.5, Pop SD - 1.71"],
  ["Lost numbers", "4, 8, 15, 16, 23, 42", "Mean: 18, SD - 13.7"],
];

export default function StandardDeviationCalculator() {
  const [input, setInput] = useState("4, 8, 15, 16, 23, 42");

  const stats = useMemo(() => {
    const nums = input.split(/[\s,;]+/).map(Number).filter(n => !isNaN(n));
    if (nums.length < 2) return null;
    const n = nums.length;
    const mean = nums.reduce((s, x) => s + x, 0) / n;
    const variancePop = nums.reduce((s, x) => s + Math.pow(x - mean, 2), 0) / n;
    const varianceSamp = nums.reduce((s, x) => s + Math.pow(x - mean, 2), 0) / (n - 1);
    const sdPop = Math.sqrt(variancePop);
    const sdSamp = Math.sqrt(varianceSamp);
    const sorted = [...nums].sort((a, b) => a - b);
    const median = n % 2 === 0 ? (sorted[n / 2 - 1] + sorted[n / 2]) / 2 : sorted[Math.floor(n / 2)];
    const cv = (sdSamp / Math.abs(mean)) * 100;
    return { n, mean, sdPop, sdSamp, variancePop, varianceSamp, median, min: sorted[0], max: sorted[sorted.length - 1], range: sorted[sorted.length - 1] - sorted[0], cv };
  }, [input]);

  return (
    <>
      <SEOHead
        title="Free Standard Deviation Calculator Online - Calculate Mean Median and Variance Instantly | CalcHive"
        description="Free online standard deviation calculator. Calculate standard deviation, mean, median and variance from any data set instantly. 100% free for students and researchers, no signup needed."
        canonical="/standard-deviation-calculator"
        keywords="free standard deviation calculator, standard deviation calculator online free, mean median variance calculator free, statistics calculator free online, calculate standard deviation free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Standard Deviation Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free standard deviation calculator to calculate standard deviation free plus mean, median, and variance from any data set. This standard deviation calculator online free also works as a mean median variance calculator free and statistics calculator free online.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-4">
            <label className="text-sm font-semibold text-foreground block mb-2">Data Set (comma, space, or semicolon separated)</label>
            <textarea value={input} onChange={e => setInput(e.target.value)} rows={3} className="w-full px-4 py-3 rounded-xl border border-input bg-background text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all font-mono text-sm" placeholder="e.g. 4, 8, 15, 16, 23, 42" />
          </div>
          <div className="flex flex-wrap gap-2 mb-6">
            {EXAMPLES.map(([label, data]) => (
              <button key={label} onClick={() => setInput(data)} className="text-xs px-3 py-1.5 rounded-lg border border-border bg-accent/60 hover:border-amber-400 text-muted-foreground hover:text-foreground transition-colors">{label}</button>
            ))}
          </div>
          {stats ? (
            <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Sample Standard Deviation</p>
                <p className="text-6xl font-black text-white tracking-tight" data-testid="result-sd">{stats.sdSamp.toFixed(4)}</p>
                <p className="text-white/70 text-sm mt-1">Population SD: {stats.sdPop.toFixed(4)} - n = {stats.n}</p>
              </div>
              <div className="grid grid-cols-3 gap-3">
                {[
                  { label: "Mean (Average)", value: stats.mean.toFixed(4) },
                  { label: "Median", value: stats.median.toFixed(4) },
                  { label: "Count (n)", value: String(stats.n) },
                  { label: "Sample Variance", value: stats.varianceSamp.toFixed(4) },
                  { label: "Min", value: String(stats.min) },
                  { label: "Max", value: String(stats.max) },
                  { label: "Range", value: stats.range.toFixed(2) },
                  { label: "CV (Coeff. of Variation)", value: `${stats.cv.toFixed(1)}%` },
                  { label: "Pop. Variance", value: stats.variancePop.toFixed(4) },
                ].map(({ label, value }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 text-center hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                    <p className="text-sm font-extrabold text-foreground">{value}</p>
                  </div>
                ))}
              </div>
            </motion.div>
          ) : <p className="text-center text-muted-foreground py-4">Enter at least 2 numbers to calculate statistics.</p>}
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Standard Deviation for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Mean () = BPx / n</p>
            <p>Population Variance (- = BP(x - )- / n</p>
            <p>Sample Variance (s- = BP(x - )- / (n - 1)</p>
            <p>Population SD () = -)</p>
            <p>Sample SD (s) = -</p>
            <p>Z-score = (x - mean) / SD</p>
            <p className="text-xs text-muted-foreground mt-2">CV (Coefficient of Variation) = (SD / Mean)  x  100%</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Mean Median and Variance from a Data Set</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Range", "% of Data (Normal Dist.)", "Z-Score Range", "Use Case"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Mean - 1 SD", "68.27%", "- to +1", "Normal variation"],
                  ["Mean - 2 SD", "95.45%", "- to +2", "Quality control limits"],
                  ["Mean - 3 SD", "99.73%", "- to +3", "Outlier detection"],
                  ["Mean - 4 SD", "99.994%", "- to +4", "Six Sigma quality"],
                  ["Mean - 6 SD", "99.9999998%", "- to +6", "Near perfection (Six Sigma)"],
                ].map(([range, pct, z, use]) => (
                  <tr key={range} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-amber-600 dark:text-amber-400">{range}</td>
                    <td className="py-2.5 px-4 font-bold text-foreground">{pct}</td>
                    <td className="py-2.5 px-4 font-mono text-muted-foreground">{z}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{use}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Statistics Calculator for Students and Researchers</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/standard-deviation-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



